def _ladda_tabell_data(data_text):
    rader = []
    for rad in data_text.strip().splitlines()[1:]:
        delar = rad.strip().split(';')
        if len(delar) == 3:
            rader.append((int(delar[0]), int(delar[1]), int(delar[2])))
    return rader


SKATTETABELL_34_KOL1 = _ladda_tabell_data(SKATTETABELL_34_KOL1_DATA)
SKATTETABELL_34_KOL1_PROCENT = _ladda_tabell_data(SKATTETABELL_34_KOL1_PROCENT_DATA)


def berakna_skatt(brutto):
    lon = int(round(brutto))
    if lon <= 0:
        return 0
    for min_lon, max_lon, skatt in SKATTETABELL_34_KOL1:
        if min_lon <= lon <= max_lon:
            return skatt
    for min_lon, max_lon, procent in SKATTETABELL_34_KOL1_PROCENT:
        if min_lon <= lon <= max_lon:
            return int((lon * procent / 100) + 0.5)
    return 0
